// Version C# 8+ : using declaration
void LireFichier(string chemin) {
    using StreamReader sr = new StreamReader(chemin);
    string contenu = sr.ReadToEnd();
    Console.WriteLine(contenu);
}

Problèmes :
- Masque des exceptions critiques (StackOverflowException, OutOfMemoryException, etc.)
- Empêche le débogage en avalant toutes les erreurs.
- Ne permet pas de réagir différemment selon le type d’erreur.

Meilleure version :
try {
    File.Delete("donnees.txt");
} catch (IOException ex) {
    Console.WriteLine("Erreur d’accès fichier : " + ex.Message);
} catch (UnauthorizedAccessException ex) {
    Console.WriteLine("Permission refusée : " + ex.Message);
}

public static class FileLogger
{
    public static void Log(Exception ex)
    {
        string logEntry = $"[{DateTime.Now}] {ex.GetType().Name}: {ex.Message}\n{ex.StackTrace}\n---";
        using (StreamWriter sw = new StreamWriter("log.txt", append: true))
        {
            sw.WriteLine(logEntry);
        }
    }
}

